mapper.select:
SELECT * FROM offi_complex
WHERE name = #{name} AND bjdong_code = #{bjdongCode}
LIMIT 1

SELECT EXISTS (
    SELECT 1 FROM offi_trade
    WHERE complex_id = #{complexId}
      AND deal_year  = #{dealYear}
      AND deal_month = #{dealMonth}
      AND deal_day   = #{dealDay}
      AND area       = #{area}
      AND floor      = #{floor}
)

SELECT EXISTS (
    SELECT 1 FROM offi_rent
    WHERE complex_id = #{complexId}
      AND deal_year  = #{dealYear}
      AND deal_month = #{dealMonth}
      AND area       = #{area}
      AND floor      = #{floor}
      AND deposit    = #{deposit}
)

SELECT c.id, c.name, c.sigungu, c.dong, c.lat, c.lng, CAST(AVG(t.price) AS INTEGER) AS avg_trade_price, CAST(AVG(CASE WHEN r.rent_type = '전세' THEN r.deposit END) AS INTEGER) AS avg_deposit_price FROM offi_complex c LEFT JOIN offi_trade t ON c.id = t.complex_id AND t.deal_year >= EXTRACT(YEAR FROM CURRENT_DATE)::int - 1 LEFT JOIN offi_rent r ON c.id = r.complex_id AND r.deal_year >= EXTRACT(YEAR FROM CURRENT_DATE)::int - 1 WHERE c.sigungu = #{sigungu}
AND c.dong = #{dong}
GROUP BY c.id, c.name, c.sigungu, c.dong, c.lat, c.lng ORDER BY avg_trade_price ASC NULLS LAST LIMIT 100
